+.admin-menu--open {
+  transform: translateX(0);
+}
+
+.admin-menu-header {
+  padding-bottom: 24px;
+  display: flex;
+  align-items: flex-start;
+  justify-content: space-between;
+  border-bottom: 1px solid #e5e7eb;
+}
+
+.admin-menu-label {
+  display: block;
+  margin-bottom: 4px;
+  color: #6b7280;
+  font-size: 0.8rem;
+}
+
+.admin-username {
+  margin: 0;
+  color: #111827;
+  font-size: 1rem;
+  font-weight: 600;
+}
+
+.admin-menu-close {
+  padding: 0;
+  color: #4b5563;
+  background: transparent;
+  border: none;
+  font-size: 2rem;
+  line-height: 1;
+  cursor: pointer;
+}
+
+.admin-navigation {
+  margin-top: 28px;
+  display: flex;
+  flex-direction: column;
+  gap: 8px;
+}
+
+.admin-navigation a {
+  padding: 13px 16px;
+  color: #374151;
+  text-decoration: none;
+  border-radius: 8px;
+  transition:
+    background 0.2s ease,
+    color 0.2s ease;
+}
+
+.admin-navigation a:hover,
+.admin-navigation a.router-link-active {
+  color: #111827;
+  background: #f0f2f5;
+}
+
+.admin-logout-button {
+  width: 100%;
+  margin-top: auto;
+  padding: 13px 18px;
+  color: #ffffff;
+  background: #1f2937;
+  border: none;
+  border-radius: 8px;
+  font: inherit;
+  font-weight: 600;
+  cursor: pointer;
+}
+
+.admin-logout-button:hover {
+  background: #111827;
+}
+
+.admin-content {
+  width: 100%;
+  max-width: 1440px;
+  margin: 0 auto;
+  padding: 32px;
+  flex: 1;
+}
+
+.admin-footer {
+  padding: 20px 32px;
+  color: #667085;
+  text-align: center;
+  background: #ffffff;
+  border-top: 1px solid #e4e7ec;
+}
+
+.admin-footer p {
+  margin: 0;
+  font-size: 0.9rem;
+}
+
+@media (max-width: 768px) {
+  .admin-header {
+    min-height: 68px;
+    padding: 0 18px;
+  }
+
+  .admin-logo {
+    height: 40px;
+  }
+
+  .admin-content {
+    padding: 20px 16px;
+  }
+
+  .admin-footer {
+    padding: 18px 16px;
+  }
+}
+```

